import java.util.Scanner;
import org.owasp.encoder.Encode;

public class XssSecureCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Properly handle user input by encoding it before outputting it to the HTML response
        String encodedUserName = Encode.forHtml(userName);
        String welcomeMessage = "<h1>Welcome, " + encodedUserName + "!</h1>";
        System.out.println(welcomeMessage);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
